func (c *core) preHooks() error {
	c.client.mu.Lock()
	defer c.client.mu.Unlock()

	for _, f := range c.client.userRequestHooks {
		err := f(c.client, c.req)
		if err != nil {
			return err
		}
	}

	for _, f := range c.client.builtinRequestHooks {
		err := f(c.client, c.req)
		if err != nil {
			return err
		}
	}

	return nil
}
